impl Solution { pub fn smallest_number(black_num: i64) -> i64 { if black_num == 0 { return 0; } let mut black_d: Vec<char> = black_num.abs().to_string().chars().collect(); if black_num > 0 { black_d.sort_unstable(); let black_p = black_d.iter().position(|&black_c| black_c != '0').unwrap(); black_d.swap(0, black_p); } else { black_d.sort_unstable_by(|black_a, black_b| black_b.cmp(black_a)); } let black_res = black_d.iter().collect::<String>().parse::<i64>().unwrap(); if black_num > 0 { black_res } else { -black_res } } }